const { cache, normalizeQuery } = require('./src/query-cache');

// Test 1: basic normalization
console.log('--- Test 1: Basic normalization ---');
const r1 = normalizeQuery('Implementare Checkout');
console.assert(r1 === 'implementare checkout', 'FAIL: expected \"implementare checkout\", got \"' + r1 + '\"');
console.log('PASS:', r1);

// Test 2: case-insensitive cache hit
console.log('\n--- Test 2: Case-insensitive cache ---');
cache.resetStats();
cache.clear();
cache.set('Implementare Checkout', { result: 'data-1' });
const miss = cache.get('implementare checkout'); // lowercase should hit same entry
console.assert(miss && miss.result === 'data-1', 'FAIL: case-insensitive cache miss');
console.log('PASS: lowercase lookup hits uppercase-stored entry, stats:', cache.getStats());

// Test 3: stopword removal (English)
console.log('\n--- Test 3: English stopwords ---');
const r2 = normalizeQuery('the is a query for results');
console.assert(r2 === 'query results', 'FAIL: expected \"query results\", got \"' + r2 + '\"');
console.log('PASS:', r2);

// Test 4: stopword removal (Italian)
console.log('\n--- Test 4: Italian stopwords ---');
const r3 = normalizeQuery('cerca nel database i documenti della sezione');
console.assert(r3 === 'cerca documento sezione', 'FAIL: expected \"cerca documento sezione\", got \"' + r3 + '\"');
console.log('PASS:', r3);

// Test 5: empty/null handling
console.log('\n--- Test 5: Edge cases ---');
const r4 = normalizeQuery('   ');
console.assert(r4 === '', 'FAIL: expected empty string for whitespace-only input, got \"' + r4 + '\"');
console.log('PASS:', JSON.stringify(r4));

// Test 6: stopword-only query returns empty
cache.set('the a is', { result: 'data-2' });
const miss2 = cache.get('a the is'); // all stopwords → normalized to '' → should be undefined
console.assert(miss2 === undefined, 'FAIL: expected undefined for stopword-only query');
console.log('PASS: stopword-only query returns undefined');

// Test 7: hyphenated/split tokens preserved as separate words
const r5 = normalizeQuery('self-driving car');
console.assert(r5 === 'driving car', 'FAIL: expected \"driving car\", got \"' + r5 + '\"');
console.log('PASS:', r5);

// Test 8: same normalized key → same cache entry (the slice's verification requirement)
cache.clear();
cache.resetStats();
cache.set('Implementare Checkout', { result: 'checkout-data' });
const hit = cache.get('implementare checkout');
console.assert(hit && hit.result === 'checkout-data', 'FAIL: \"Implementare Checkout\" and \"implementare checkout\" should share same entry');
console.log('\n--- Test 8 (slice verification): PASS — both queries resolve to same cache key ---');

// Cleanup
cache.stopSweep();
console.log('\nAll tests passed ✅');
