const { cache, normalizeQuery } = require('./src/query-cache');
let passed = 0; let failed = 0;

function assert(cond, msg) { if (cond) { passed++; console.log('✅', msg); } else { failed++; console.log('❌', msg); process.exitCode = 1; } }

// T02 verification: case-insensitive cache hit
cache.clear(); cache.resetStats();
cache.set('Implementare Checkout', { result: 'checkout-data' });
const hit = cache.get('implementare checkout');
assert(hit && hit.result === 'checkout-data', 'T02 verify: \"Implementare Checkout\" and \"implementare checkout\" → same entry');

// Stopword EN
assert(normalizeQuery('the is a query for results') === 'query results', 'EN stopwords filtered correctly');

// Stopword IT  
assert(normalizeQuery('cerca nel database i documenti della sezione') === 'cerca database documenti sezione', 'IT stopwords filtered correctly');

// Empty input
assert(normalizeQuery('   ') === '', 'whitespace-only → empty string');

// All-stopwords query returns undefined from cache
cache.clear(); cache.resetStats();
const miss = cache.get('a the is');
assert(miss === undefined, 'all-stopword query → cache miss (normalized to \"\")');

console.log('\nResults: ' + passed + '/' + (passed+failed) + ' tests passed' + (failed ? ' ❌' : ' ✅'));
cache.stopSweep();
